import { isUndefined } from 'lodash-es';
import { type MouseEvent as ReactMouseEvent, type RefObject } from 'react';

import { useAnnotationsSelectionState } from './store/selectors.js';
import {
  useSetStateSelection,
  useSetStateTooltip,
} from './store/state-setters.js';
import { useMarkersInteractions } from './useMarkersInteractions.js';
import { initialState } from '../providers/AnnotationsDataInitialState.js';
import type { AnnotationsMarkerGroup } from '../types/annotations.js';
import type { SelectionState } from '../types/state.js';
import { calculateTooltipPosition } from '../utils/calculate-tooltip-position.js';

export const useMarkerEventHandlers = (
  annotationsContainerRef: RefObject<HTMLDivElement> | undefined,
) => {
  const updateTooltipState = useSetStateTooltip();
  const updateTooltipSelection = useSetStateSelection();

  const { pinnedGroup } = useAnnotationsSelectionState();
  const onMarkersInteraction = useMarkersInteractions();

  const isTooltipPinned = !isUndefined(pinnedGroup);
  const handleMouseMove = (event: ReactMouseEvent) => {
    if (isTooltipPinned || !annotationsContainerRef?.current) {
      return;
    }

    const { clientX, clientY } = event;
    const absolutePosition = calculateTooltipPosition(clientX, clientY);
    const annotationsContainerRect =
      annotationsContainerRef.current.getBoundingClientRect();
    updateTooltipState({
      position: absolutePosition,
      relativePosition: {
        x: absolutePosition.x - annotationsContainerRect.left,
        y: absolutePosition.y - annotationsContainerRect.top,
      },
    });
  };

  const handleMouseEnter =
    (
      markerId: string,
      groupId: string,
      annotationsGroup: AnnotationsMarkerGroup[],
    ) =>
    (event: ReactMouseEvent) => {
      if (isTooltipPinned || !annotationsContainerRef?.current) {
        return;
      }

      const { clientX, clientY } = event;
      const absolutePosition = calculateTooltipPosition(clientX, clientY);
      const annotationsContainerRect =
        annotationsContainerRef.current.getBoundingClientRect();
      updateTooltipState({
        position: absolutePosition,
        relativePosition: {
          x: absolutePosition.x - annotationsContainerRect.left,
          y: absolutePosition.y - annotationsContainerRect.top,
        },
        data: annotationsGroup,
        visibility: true,
      });

      const selectionState: SelectionState = {
        hoveredItem: markerId,
        hoveredGroup: groupId,
        data: annotationsGroup,
      };

      updateTooltipSelection(selectionState);
      onMarkersInteraction?.(selectionState);
    };

  const handleClick =
    (groupId: string, annotationsGroup: AnnotationsMarkerGroup[]) =>
    (event: ReactMouseEvent) => {
      event.stopPropagation();

      const { clientX, clientY } = event;
      const newSelection = {
        hoveredGroup: groupId,
        data: annotationsGroup,
        pinnedGroup: isTooltipPinned ? undefined : groupId, // if tooltip was already pinned, unpin
      };

      updateTooltipState({
        position: calculateTooltipPosition(clientX, clientY),
        data: annotationsGroup,
        visibility: true,
        pinned: !isTooltipPinned, // if tooltip was already pinned, show updated info but unpin
      });
      updateTooltipSelection(newSelection);
      onMarkersInteraction?.(newSelection);
    };

  const handleMouseLeave = () => {
    if (isTooltipPinned) {
      return;
    }

    updateTooltipState(initialState.tooltip);
    updateTooltipSelection(initialState.selection);
    onMarkersInteraction?.(initialState.selection);
  };

  return {
    handleMouseEnter,
    handleMouseMove,
    handleMouseLeave,
    handleClick,
  };
};
